// Fuente serif embebida para generación de PDF (Tinos, SIL Open Font License -- Google Fonts),
// métricamente compatible con Times New Roman (mismos anchos de carácter por diseño).
// Se usa SOLO al generar PDF (generatePDFFromHtml), no en el HTML guardado/preview: el
// entorno serverless de Vercel (@sparticuz/chromium-min) no trae NINGUNA fuente del sistema
// -- ni Times New Roman ni ningún otro serif -- solo bundlea 'Open Sans' como fallback. Sin
// esto, el CSS pide 'Times New Roman, Times, serif' y Chromium headless usa una fuente
// completamente distinta (anchos de carácter distintos), rompiendo el ajuste de línea de
// forma impredecible en producción aunque el HTML/CSS sea idéntico al preview.
// No se necesita en el preview del navegador: ahí el sistema operativo del usuario sí trae
// Times New Roman (Windows/Mac) o un fallback serif razonable.

const TINOS_REGULAR_B64 = ''

const TINOS_BOLD_B64 = ''

const TINOS_ITALIC_B64 = ''

const TINOS_BOLDITALIC_B64 = ''

export const PDF_EMBEDDED_FONT_CSS = `<style>
@font-face{font-family:'Times New Roman';font-weight:normal;font-style:normal;src:url(data:font/truetype;charset=utf-8;base64,${TINOS_REGULAR_B64}) format('truetype')}
@font-face{font-family:'Times New Roman';font-weight:bold;font-style:normal;src:url(data:font/truetype;charset=utf-8;base64,${TINOS_BOLD_B64}) format('truetype')}
@font-face{font-family:'Times New Roman';font-weight:normal;font-style:italic;src:url(data:font/truetype;charset=utf-8;base64,${TINOS_ITALIC_B64}) format('truetype')}
@font-face{font-family:'Times New Roman';font-weight:bold;font-style:italic;src:url(data:font/truetype;charset=utf-8;base64,${TINOS_BOLDITALIC_B64}) format('truetype')}
</style>`
